def get_onboarding_morning(day):
    if day in ONBOARDING:
        return ONBOARDING[day]["morning"]
    return None

def get_onboarding_evening(day):
    if day in ONBOARDING:
        return ONBOARDING[day]["evening"]
    return None

def is_onboarding_complete(day):
    return day > 7
